using ContosoUniversity.Data;
using Microsoft.EntityFrameworkCore;
using System;

namespace ContosoUniversity.Tests.Helpers
{
    public static class TestDbContextFactory
    {
        public static SchoolContext Create(string dbName = null)
        {
            dbName ??= Guid.NewGuid().ToString();
            var options = new DbContextOptionsBuilder<SchoolContext>()
                .UseInMemoryDatabase(databaseName: dbName)
                .Options;
            var context = new SchoolContext(options);
            context.Database.EnsureCreated();
            return context;
        }
    }
}

using ContosoUniversity.Data;
using ContosoUniversity.Models;
using System;
using System.Collections.Generic;

namespace ContosoUniversity.Tests.Helpers
{
    public static class TestHelper
    {
        public static void SeedStudents(SchoolContext context)
        {
            context.Students.AddRange(
                new Student { FirstMidName = "Carson", LastName = "Alexander", EnrollmentDate = DateTime.Parse("2020-09-01") },
                new Student { FirstMidName = "Meredith", LastName = "Alonso", EnrollmentDate = DateTime.Parse("2021-09-01") },
                new Student { FirstMidName = "Arturo", LastName = "Anand", EnrollmentDate = DateTime.Parse("2021-09-01") }
            );
            context.SaveChanges();
        }

        public static void SeedInstructors(SchoolContext context)
        {
            context.Instructors.AddRange(
                new Instructor
                {
                    FirstMidName = "Kim",
                    LastName = "Abercrombie",
                    HireDate = DateTime.Parse("1995-03-11"),
                    CourseAssignments = new List<CourseAssignment>(),
                    OfficeAssignment = new OfficeAssignment { Location = "Smith 17" }
                },
                new Instructor
                {
                    FirstMidName = "Fadi",
                    LastName = "Fakhouri",
                    HireDate = DateTime.Parse("2002-07-06"),
                    CourseAssignments = new List<CourseAssignment>()
                }
            );
            context.SaveChanges();
        }

        public static void SeedDepartments(SchoolContext context)
        {
            SeedInstructors(context);
            var instructors = new List<Instructor>(context.Instructors);
            context.Departments.AddRange(
                new Department { Name = "English", Budget = 350000, StartDate = DateTime.Parse("2007-09-01"), InstructorID = instructors[0].ID },
                new Department { Name = "Mathematics", Budget = 100000, StartDate = DateTime.Parse("2007-09-01"), InstructorID = instructors[1].ID }
            );
            context.SaveChanges();
        }

        public static void SeedCourses(SchoolContext context)
        {
            SeedDepartments(context);
            var departments = new List<Department>(context.Departments);
            context.Courses.AddRange(
                new Course { CourseID = 1050, Title = "Chemistry", Credits = 3, DepartmentID = departments[0].DepartmentID },
                new Course { CourseID = 4022, Title = "Microeconomics", Credits = 3, DepartmentID = departments[1].DepartmentID }
            );
            context.SaveChanges();
        }

        public static void SeedFullData(SchoolContext context)
        {
            SeedCourses(context);
            SeedStudents(context);

            var students = new List<Student>(context.Students);
            context.Enrollments.AddRange(
                new Enrollment { StudentID = students[0].ID, CourseID = 1050, Grade = Grade.A },
                new Enrollment { StudentID = students[0].ID, CourseID = 4022, Grade = Grade.C },
                new Enrollment { StudentID = students[1].ID, CourseID = 1050, Grade = Grade.B }
            );
            context.SaveChanges();
        }
    }
}

