        {
            var student = new Student();
            Assert.IsAssignableFrom<Person>(student);
        }

        [Fact]
        public void Student_EnrollmentDate_CanBeSet()
        {
            var date = new DateTime(2020, 9, 1);
            var student = new Student { EnrollmentDate = date };
            Assert.Equal(date, student.EnrollmentDate);
        }

        [Fact]
        public void Student_Enrollments_CanBeInitialized()
        {
            var student = new Student
            {
                Enrollments = new List<Enrollment>
                {
                    new Enrollment { CourseID = 1, Grade = Grade.A },
                    new Enrollment { CourseID = 2, Grade = Grade.B }
                }
            };
            Assert.Equal(2, student.Enrollments.Count);
        }

        [Fact]
        public void Student_Validation_RequiresLastName()
        {
            var student = new Student
            {
                FirstMidName = "Test",
                EnrollmentDate = DateTime.Today
            };
            var results = ValidateModel(student);
            Assert.Contains(results, v => v.MemberNames.Contains("LastName"));
        }

        [Fact]
        public void Student_Validation_RequiresFirstMidName()
        {
            var student = new Student
            {
                LastName = "Test",
                EnrollmentDate = DateTime.Today
            };
            var results = ValidateModel(student);
            Assert.Contains(results, v => v.MemberNames.Contains("FirstMidName"));
        }

        [Fact]
        public void Student_Validation_LastNameMaxLength50()
        {
            var student = new Student
            {
                FirstMidName = "Test",
                LastName = new string('A', 51),
                EnrollmentDate = DateTime.Today
            };
            var results = ValidateModel(student);
            Assert.Contains(results, v => v.MemberNames.Contains("LastName"));
        }

        [Fact]
        public void Student_Validation_FirstNameMaxLength50()
        {
            var student = new Student
            {
                FirstMidName = new string('A', 51),
                LastName = "Test",
                EnrollmentDate = DateTime.Today
            };
            var results = ValidateModel(student);
            Assert.Contains(results, v => v.MemberNames.Contains("FirstMidName"));
        }

        [Fact]
        public void Student_Validation_ValidStudent_Passes()
        {
            var student = new Student
            {
                FirstMidName = "Carson",
                LastName = "Alexander",
                EnrollmentDate = DateTime.Today
            };
            var results = ValidateModel(student);
            Assert.Empty(results);
        }

        private static List<ValidationResult> ValidateModel(object model)
        {
            var validationResults = new List<ValidationResult>();
            var ctx = new ValidationContext(model);
            Validator.TryValidateObject(model, ctx, validationResults, true);
            return validationResults;
        }
    }
}

