        public void Course_Validation_CreditsOutOfRange_Fails()
        {
            var course = new Course { CourseID = 1, Title = "Chemistry", Credits = 6, DepartmentID = 1 };
            var results = ValidateModel(course);
            Assert.Contains(results, v => v.MemberNames.Contains("Credits"));
        }

