        public void Course_Validation_CreditsNegative_Fails()
        {
            var course = new Course { CourseID = 1, Title = "Chemistry", Credits = -1, DepartmentID = 1 };
            var results = ValidateModel(course);
            Assert.Contains(results, v => v.MemberNames.Contains("Credits"));
        }

        [Fact]
        public void Course_Validation_ValidCourse_Passes()
        {
            var course = new Course { CourseID = 1, Title = "Chemistry", Credits = 3, DepartmentID = 1 };
            var results = ValidateModel(course);
            Assert.Empty(results);
        }

