        public void Course_Collections_CanBeInitialized()
        {
            var course = new Course
            {
                Enrollments = new List<Enrollment> { new Enrollment() },
                CourseAssignments = new List<CourseAssignment> { new CourseAssignment() }
            };
            Assert.Single(course.Enrollments);
            Assert.Single(course.CourseAssignments);
        }

        private static List<ValidationResult> ValidateModel(object model)
        {
            var results = new List<ValidationResult>();
            Validator.TryValidateObject(model, new ValidationContext(model), results, true);
            return results;
        }
    }
