namespace ContosoUniversity.Tests.Models
{
    public class NotificationTests
    {
        [Fact]
        public void Notification_Properties_CanBeSet()
        {
            var now = DateTime.Now;
            var notification = new Notification
            {
                Id = 1,
                EntityType = "Student",
                EntityId = "42",
                Operation = "CREATE",
                Message = "New Student created",
                CreatedAt = now,
                CreatedBy = "admin",
                IsRead = false,
                ReadAt = null
            };
            Assert.Equal(1, notification.Id);
            Assert.Equal("Student", notification.EntityType);
            Assert.Equal("42", notification.EntityId);
            Assert.Equal("CREATE", notification.Operation);
            Assert.Equal("New Student created", notification.Message);
            Assert.Equal(now, notification.CreatedAt);
            Assert.Equal("admin", notification.CreatedBy);
            Assert.False(notification.IsRead);
            Assert.Null(notification.ReadAt);
        }

        [Fact]
        public void Notification_ReadAt_CanBeSet()
        {
            var readTime = DateTime.Now;
            var notification = new Notification { IsRead = true, ReadAt = readTime };
            Assert.True(notification.IsRead);
            Assert.Equal(readTime, notification.ReadAt);
        }

        [Fact]
        public void EntityOperation_Values_AreCorrect()
        {
            Assert.Equal(0, (int)EntityOperation.CREATE);
            Assert.Equal(1, (int)EntityOperation.UPDATE);
            Assert.Equal(2, (int)EntityOperation.DELETE);
        }

        [Fact]
        public void Notification_Validation_RequiresEntityType()
        {
            var notification = new Notification
            {
                EntityId = "1",
                Operation = "CREATE",
                Message = "Test",
                CreatedAt = DateTime.Now
            };
            var results = ValidateModel(notification);
            Assert.Contains(results, v => v.MemberNames.Contains("EntityType"));
        }

        [Fact]
        public void Notification_Validation_RequiresMessage()
        {
            var notification = new Notification
            {
                EntityType = "Student",
                EntityId = "1",
                Operation = "CREATE",
                CreatedAt = DateTime.Now
            };
            var results = ValidateModel(notification);
            Assert.Contains(results, v => v.MemberNames.Contains("Message"));
        }

        private static List<ValidationResult> ValidateModel(object model)
        {
            var results = new List<ValidationResult>();
            Validator.TryValidateObject(model, new ValidationContext(model), results, true);
            return results;
        }
    }
}

