        {
            var dept = new Department { RowVersion = new byte[] { 1, 2, 3, 4 } };
            Assert.Equal(new byte[] { 1, 2, 3, 4 }, dept.RowVersion);
        }

        [Fact]
        public void Department_Validation_NameTooShort_Fails()
        {
            var dept = new Department { Name = "AB", Budget = 100000, StartDate = DateTime.Today };
