            var results = ValidateModel(dept);
            Assert.Contains(results, v => v.MemberNames.Contains("Name"));
        }

        [Fact]
        public void Department_Courses_CanBeInitialized()
        {
            var dept = new Department { Courses = new List<Course> { new Course { CourseID = 1 } } };
            Assert.Single(dept.Courses);
        }

        private static List<ValidationResult> ValidateModel(object model)
        {
            var results = new List<ValidationResult>();
            Validator.TryValidateObject(model, new ValidationContext(model), results, true);
            return results;
        }
    }
}

