using ContosoUniversity.Models;
using Xunit;

namespace ContosoUniversity.Tests.Models
{
    public class EnrollmentTests
    {
        [Fact]
        public void Enrollment_Properties_CanBeSet()
        {
            var enrollment = new Enrollment
            {
                EnrollmentID = 1,
                CourseID = 1050,
                StudentID = 1,
                Grade = Grade.A
            };
            Assert.Equal(1, enrollment.EnrollmentID);
            Assert.Equal(1050, enrollment.CourseID);
            Assert.Equal(1, enrollment.StudentID);
            Assert.Equal(Grade.A, enrollment.Grade);
        }

        [Fact]
        public void Enrollment_Grade_CanBeNull()
        {
            var enrollment = new Enrollment();
            Assert.Null(enrollment.Grade);
        }

        [Fact]
        public void Enrollment_NavigationProperties_CanBeSet()
        {
            var student = new Student { FirstMidName = "Test", LastName = "User" };
            var course = new Course { CourseID = 1, Title = "Test" };
            var enrollment = new Enrollment { Student = student, Course = course };
            Assert.NotNull(enrollment.Student);
            Assert.NotNull(enrollment.Course);
        }

        [Theory]
        [InlineData(Grade.A)]
        [InlineData(Grade.B)]
        [InlineData(Grade.C)]
        [InlineData(Grade.D)]
        [InlineData(Grade.F)]
        public void Grade_AllValues_AreValid(Grade grade)
        {
            var enrollment = new Enrollment { Grade = grade };
            Assert.Equal(grade, enrollment.Grade);
        }
    }
}

