        public void Notification_Validation_RequiresEntityType()
        {
            var notification = new Notification
            {
                EntityId = "1",
                Operation = "CREATE",
                Message = "Test",
                CreatedAt = DateTime.Now
            };
            var results = ValidateModel(notification);
            Assert.Contains(results, v => v.MemberNames.Contains("EntityType"));
        }

