using ContosoUniversity.Models;
using ContosoUniversity.Services;
using System;
using Xunit;

namespace ContosoUniversity.Tests.Services
{
    public class NotificationServiceTests : IDisposable
    {
        private readonly NotificationService _service;

        public NotificationServiceTests()
        {
            _service = new NotificationService();
            // Drain any leftover notifications from static queue
            while (_service.ReceiveNotification() != null) { }
        }

        public void Dispose()
        {
            _service.Dispose();
        }

        [Fact]
        public void SendNotification_WithDisplayName_CreatesCorrectMessage()
        {
            _service.SendNotification("Student", "1", "Carson Alexander", EntityOperation.CREATE, "admin");
            var notification = _service.ReceiveNotification();

            Assert.NotNull(notification);
            Assert.Equal("Student", notification.EntityType);
            Assert.Equal("1", notification.EntityId);
            Assert.Equal("CREATE", notification.Operation);
            Assert.Contains("Carson Alexander", notification.Message);
            Assert.Contains("created", notification.Message);
            Assert.Equal("admin", notification.CreatedBy);
            Assert.False(notification.IsRead);
        }

        [Fact]
        public void SendNotification_WithoutDisplayName_UsesEntityIdInMessage()
        {
            _service.SendNotification("Course", "42", EntityOperation.UPDATE, "teacher");
            var notification = _service.ReceiveNotification();

            Assert.NotNull(notification);
            Assert.Contains("ID: 42", notification.Message);
            Assert.Contains("updated", notification.Message);
        }

        [Fact]
        public void SendNotification_Delete_CreatesDeleteMessage()
        {
            _service.SendNotification("Department", "5", "Engineering", EntityOperation.DELETE);
            var notification = _service.ReceiveNotification();

            Assert.NotNull(notification);
            Assert.Contains("deleted", notification.Message);
            Assert.Contains("Engineering", notification.Message);
        }

        [Fact]
        public void SendNotification_WithoutUserName_DefaultsToSystem()
        {
            _service.SendNotification("Student", "1", EntityOperation.CREATE);
            var notification = _service.ReceiveNotification();

            Assert.NotNull(notification);
            Assert.Equal("System", notification.CreatedBy);
        }

        [Fact]
        public void ReceiveNotification_WhenQueueEmpty_ReturnsNull()
        {
            var notification = _service.ReceiveNotification();
            Assert.Null(notification);
        }

        [Fact]
        public void ReceiveNotification_DequeueFIFO()
        {
            _service.SendNotification("A", "1", EntityOperation.CREATE);
            _service.SendNotification("B", "2", EntityOperation.UPDATE);

            var first = _service.ReceiveNotification();
            var second = _service.ReceiveNotification();

            Assert.Equal("A", first.EntityType);
            Assert.Equal("B", second.EntityType);
        }

        [Fact]
        public void SendNotification_SetsCreatedAt()
        {
            var before = DateTime.Now;
            _service.SendNotification("Student", "1", EntityOperation.CREATE);
            var after = DateTime.Now;

            var notification = _service.ReceiveNotification();
            Assert.InRange(notification.CreatedAt, before, after);
        }

        [Fact]
        public void MarkAsRead_DoesNotThrow()
        {
            // No-op implementation, just verify it doesn't throw
            var ex = Record.Exception(() => _service.MarkAsRead(1));
            Assert.Null(ex);
        }

        [Fact]
        public void SendNotification_CreateOperation_MessageFormat()
        {
            _service.SendNotification("Student", "1", "John Doe", EntityOperation.CREATE);
            var notification = _service.ReceiveNotification();
            Assert.Equal("New Student 'John Doe' has been created", notification.Message);
        }

        [Fact]
        public void SendNotification_UpdateOperation_MessageFormat()
        {
            _service.SendNotification("Course", "101", "Chemistry", EntityOperation.UPDATE);
            var notification = _service.ReceiveNotification();
            Assert.Equal("Course 'Chemistry' has been updated", notification.Message);
        }

        [Fact]
        public void SendNotification_DeleteOperation_MessageFormat()
        {
            _service.SendNotification("Department", "3", "Math", EntityOperation.DELETE);
            var notification = _service.ReceiveNotification();
            Assert.Equal("Department 'Math' has been deleted", notification.Message);
        }

        [Fact]
        public void SendNotification_WithoutDisplayName_CreateMessageFormat()
        {
            _service.SendNotification("Student", "42", EntityOperation.CREATE);
            var notification = _service.ReceiveNotification();
            Assert.Equal("New Student (ID: 42) has been created", notification.Message);
        }

        [Fact]
        public void SendNotification_MultipleNotifications_AllReceived()
        {
            for (int i = 0; i < 5; i++)
            {
                _service.SendNotification("Test", i.ToString(), EntityOperation.CREATE);
            }

            int count = 0;
            while (_service.ReceiveNotification() != null) count++;
            Assert.Equal(5, count);
        }

        [Fact]
        public void Dispose_CanBeCalledMultipleTimes()
        {
            var service = new NotificationService();
            var ex = Record.Exception(() =>
            {
                service.Dispose();
                service.Dispose();
            });
            Assert.Null(ex);
        }
    }
}

using System;
using System.Collections.Generic;
using System.Linq;
using Xunit;

namespace ContosoUniversity.Tests
{
    public class PaginatedListTests
    {
        [Fact]
        public void Constructor_SetsProperties()
        {
            var items = new List<int> { 1, 2, 3 };
            var list = new PaginatedList<int>(items, 10, 2, 3);

            Assert.Equal(2, list.PageIndex);
            Assert.Equal(4, list.TotalPages); // ceil(10/3) = 4
            Assert.Equal(3, list.Count);
        }

        [Fact]
        public void HasPreviousPage_ReturnsFalse_OnFirstPage()
        {
            var list = new PaginatedList<int>(new List<int> { 1 }, 5, 1, 3);
            Assert.False(list.HasPreviousPage);
        }

        [Fact]
        public void HasPreviousPage_ReturnsTrue_OnSecondPage()
        {
            var list = new PaginatedList<int>(new List<int> { 1 }, 5, 2, 3);
            Assert.True(list.HasPreviousPage);
        }

        [Fact]
        public void HasNextPage_ReturnsTrue_WhenNotLastPage()
        {
            var list = new PaginatedList<int>(new List<int> { 1 }, 10, 1, 3);
            Assert.True(list.HasNextPage);
        }

        [Fact]
        public void HasNextPage_ReturnsFalse_OnLastPage()
        {
            var list = new PaginatedList<int>(new List<int> { 1 }, 10, 4, 3);
            Assert.False(list.HasNextPage);
        }

        [Fact]
        public void Create_ReturnsCorrectPage()
        {
            var source = Enumerable.Range(1, 20).AsQueryable();
            var result = PaginatedList<int>.Create(source, 2, 5);

            Assert.Equal(2, result.PageIndex);
            Assert.Equal(4, result.TotalPages);
            Assert.Equal(5, result.Count);
            Assert.Equal(new[] { 6, 7, 8, 9, 10 }, result.ToArray());
        }

        [Fact]
        public void Create_FirstPage_ReturnsCorrectItems()
        {
            var source = Enumerable.Range(1, 10).AsQueryable();
            var result = PaginatedList<int>.Create(source, 1, 3);

            Assert.Equal(1, result.PageIndex);
            Assert.Equal(4, result.TotalPages);
            Assert.Equal(new[] { 1, 2, 3 }, result.ToArray());
        }

        [Fact]
        public void Create_LastPage_ReturnsRemainingItems()
        {
            var source = Enumerable.Range(1, 10).AsQueryable();
            var result = PaginatedList<int>.Create(source, 4, 3);

            Assert.Equal(4, result.PageIndex);
            Assert.Single(result);
            Assert.Equal(10, result[0]);
        }

        [Fact]
        public void Create_SinglePage_NoNavigation()
        {
            var source = Enumerable.Range(1, 3).AsQueryable();
            var result = PaginatedList<int>.Create(source, 1, 10);

            Assert.Equal(1, result.PageIndex);
            Assert.Equal(1, result.TotalPages);
            Assert.False(result.HasPreviousPage);
            Assert.False(result.HasNextPage);
        }

        [Fact]
        public void TotalPages_CalculatedCorrectly_WhenExactDivision()
        {
            var list = new PaginatedList<int>(new List<int>(), 10, 1, 5);
            Assert.Equal(2, list.TotalPages);
        }

        [Fact]
        public void TotalPages_RoundsUp_WhenPartialPage()
        {
            var list = new PaginatedList<int>(new List<int>(), 11, 1, 5);
            Assert.Equal(3, list.TotalPages);
        }

        [Fact]
        public void Create_EmptySource_ReturnsEmptyList()
        {
            var source = Enumerable.Empty<int>().AsQueryable();
            var result = PaginatedList<int>.Create(source, 1, 10);
            Assert.Empty(result);
            Assert.Equal(0, result.TotalPages);
        }
    }
}

