            Assert.Equal(3, list.Count);
        }

        [Fact]
        public void HasPreviousPage_ReturnsFalse_OnFirstPage()
        {
            var list = new PaginatedList<int>(new List<int> { 1 }, 5, 1, 3);
            Assert.False(list.HasPreviousPage);
        }

        [Fact]
        public void HasPreviousPage_ReturnsTrue_OnSecondPage()
        {
            var list = new PaginatedList<int>(new List<int> { 1 }, 5, 2, 3);
            Assert.True(list.HasPreviousPage);
        }

        [Fact]
        public void HasNextPage_ReturnsTrue_WhenNotLastPage()
        {
            var list = new PaginatedList<int>(new List<int> { 1 }, 10, 1, 3);
            Assert.True(list.HasNextPage);
        }

        [Fact]
        public void HasNextPage_ReturnsFalse_OnLastPage()
        {
            var list = new PaginatedList<int>(new List<int> { 1 }, 10, 4, 3);
            Assert.False(list.HasNextPage);
        }

        [Fact]
        public void Create_ReturnsCorrectPage()
        {
            var source = Enumerable.Range(1, 20).AsQueryable();
            var result = PaginatedList<int>.Create(source, 2, 5);

            Assert.Equal(2, result.PageIndex);
            Assert.Equal(4, result.TotalPages);
            Assert.Equal(5, result.Count);
            Assert.Equal(new[] { 6, 7, 8, 9, 10 }, result.ToArray());
        }

        [Fact]
        public void Create_FirstPage_ReturnsCorrectItems()
        {
            var source = Enumerable.Range(1, 10).AsQueryable();
            var result = PaginatedList<int>.Create(source, 1, 3);

            Assert.Equal(1, result.PageIndex);
            Assert.Equal(4, result.TotalPages);
            Assert.Equal(new[] { 1, 2, 3 }, result.ToArray());
        }

        [Fact]
        public void Create_LastPage_ReturnsRemainingItems()
        {
            var source = Enumerable.Range(1, 10).AsQueryable();
            var result = PaginatedList<int>.Create(source, 4, 3);

            Assert.Equal(4, result.PageIndex);
            Assert.Single(result);
            Assert.Equal(10, result[0]);
        }

        [Fact]
        public void Create_SinglePage_NoNavigation()
        {
