namespace ContosoUniversity.Tests.Controllers
{
    public class InstructorsControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly InstructorsController _controller;

        public InstructorsControllerTests()
        {
            _context = TestDbContextFactory.Create();
            _controller = new InstructorsController(_context);
        }

        public void Dispose()
        {
            _controller.Dispose();
            _context.Dispose();
        }

        [Fact]
        public void Index_ReturnsViewWithInstructorIndexData()
        {
            TestHelper.SeedInstructors(_context);
            var result = _controller.Index(null, null);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsType<InstructorIndexData>(viewResult.Model);
            Assert.NotNull(model.Instructors);
            Assert.Equal(2, model.Instructors.Count());
        }

        [Fact]
        public void Index_WithInstructorId_PopulatesCourses()
        {
            TestHelper.SeedCourses(_context);
            var instructor = _context.Instructors.First();
            _context.CourseAssignments.Add(new CourseAssignment
            {
                InstructorID = instructor.ID,
                CourseID = 1050
            });
            _context.SaveChanges();

            var result = _controller.Index(instructor.ID, null);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsType<InstructorIndexData>(viewResult.Model);
            Assert.NotNull(model.Courses);
            Assert.Single(model.Courses);
        }

        [Fact]
        public void Index_OrdersInstructorsByLastName()
        {
            TestHelper.SeedInstructors(_context);
            var result = _controller.Index(null, null);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsType<InstructorIndexData>(viewResult.Model);
            var instructors = model.Instructors.ToList();
            Assert.Equal("Abercrombie", instructors[0].LastName);
            Assert.Equal("Fakhouri", instructors[1].LastName);
        }

        [Fact]
        public void Details_ValidId_ReturnsViewWithInstructor()
        {
            TestHelper.SeedInstructors(_context);
            var instructor = _context.Instructors.First();

            var result = _controller.Details(instructor.ID);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsType<Instructor>(viewResult.Model);
            Assert.Equal(instructor.ID, model.ID);
        }

        [Fact]
        public void Details_NullId_ReturnsBadRequest()
        {
            var result = _controller.Details(null);
            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Details_InvalidId_ReturnsNotFound()
        {
            var result = _controller.Details(999);
            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void Create_GET_ReturnsViewWithInstructorAndCourseData()
        {
            TestHelper.SeedCourses(_context);
            var result = _controller.Create();

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsType<Instructor>(viewResult.Model);
            Assert.NotNull(model.CourseAssignments);
            Assert.Empty(model.CourseAssignments);
            Assert.NotNull(viewResult.ViewData["Courses"]);
        }

        [Fact]
        public void Create_POST_ValidInstructor_RedirectsToIndex()
        {
            var instructor = new Instructor
            {
                FirstMidName = "New",
                LastName = "Instructor",
                HireDate = DateTime.Today,
                CourseAssignments = new List<CourseAssignment>()
            };

            var result = _controller.Create(instructor, null);

            var redirectResult = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirectResult.ActionName);
            Assert.Single(_context.Instructors);
        }

        [Fact]
        public void Create_POST_WithSelectedCourses_AddsCourseAssignments()
        {
            TestHelper.SeedCourses(_context);
            var instructor = new Instructor
            {
                FirstMidName = "New",
                LastName = "Instructor",
                HireDate = DateTime.Today
            };
            var selectedCourses = new[] { "1050", "4022" };

            var result = _controller.Create(instructor, selectedCourses);

            var redirectResult = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirectResult.ActionName);

            var savedInstructor = _context.Instructors
                .Include(i => i.CourseAssignments)
                .Single(i => i.LastName == "Instructor");
            Assert.Equal(2, savedInstructor.CourseAssignments.Count);
        }

        [Fact]
        public void Create_POST_InvalidModel_ReturnsView()
        {
            _controller.ModelState.AddModelError("LastName", "Required");
            var instructor = new Instructor { CourseAssignments = new List<CourseAssignment>() };

            var result = _controller.Create(instructor, null);

            Assert.IsType<ViewResult>(result);
        }

        [Fact]
        public void Delete_GET_ValidId_ReturnsViewWithInstructor()
        {
            TestHelper.SeedInstructors(_context);
            var instructor = _context.Instructors.First();

            var result = _controller.Delete(instructor.ID);

            var viewResult = Assert.IsType<ViewResult>(result);
            Assert.IsType<Instructor>(viewResult.Model);
        }

        [Fact]
        public void Delete_GET_NullId_ReturnsBadRequest()
        {
            var result = _controller.Delete(null);
            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Delete_GET_InvalidId_ReturnsNotFound()
        {
            var result = _controller.Delete(999);
            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void DeleteConfirmed_ValidId_RemovesInstructorAndRedirects()
        {
            TestHelper.SeedInstructors(_context);
            var instructor = _context.Instructors
                .Include(i => i.OfficeAssignment)
                .First();
            var initialCount = _context.Instructors.Count();

            var result = _controller.DeleteConfirmed(instructor.ID);

            var redirectResult = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirectResult.ActionName);
            Assert.Equal(initialCount - 1, _context.Instructors.Count());
        }

        [Fact]
        public void DeleteConfirmed_InstructorWithDepartment_NullifyDepartmentInstructor()
        {
            TestHelper.SeedDepartments(_context);
            var instructor = _context.Instructors.First();
            var dept = _context.Departments.First(d => d.InstructorID == instructor.ID);

            _controller.DeleteConfirmed(instructor.ID);

            var updatedDept = _context.Departments.Find(dept.DepartmentID);
            Assert.Null(updatedDept.InstructorID);
        }
    }
