{"file_text": "using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.EntityFrameworkCore;
using System;
using System.Linq;
using Xunit;

namespace ContosoUniversity.Tests
{
    public class SchoolContextTests
    {
        [Fact]
        public void CanAddAndRetrieveStudent()
        {
            using var context = TestDbContextFactory.Create();
            context.Students.Add(new Student
            {
                FirstMidName = "Test",
                LastName = "Student",
                EnrollmentDate = DateTime.Today
            });
            context.SaveChanges();

            var student = context.Students.First();
            Assert.Equal("Test", student.FirstMidName);
            Assert.Equal("Student", student.LastName);
        }

        [Fact]
        public void CanAddAndRetrieveCourse()
        {
            using var context = TestDbContextFactory.Create();
            TestHelper.SeedDepartments(context);
            var dept = context.Departments.First();
            context.Courses.Add(new Course
            {
                CourseID = 5000,
                Title = "Test Course",
                Credits = 3,
                DepartmentID = dept.DepartmentID
            });
            context.SaveChanges();

            var course = context.Courses.Find(5000);
            Assert.NotNull(course);
            Assert.Equal("Test Course", course.Title);
        }

        [Fact]
        public void CourseAssignment_HasCompositeKey()
        {
            using var context = TestDbContextFactory.Create();
            TestHelper.SeedCourses(context);

            var instructor = context.Instructors.First();
            context.CourseAssignments.Add(new CourseAssignment
            {
                CourseID = 1050,
                InstructorID = instructor.ID
            });
            context.SaveChanges();

            var assignment = context.CourseAssignments.Find(1050, instructor.ID);
            Assert.NotNull(assignment);
        }

        [Fact]
        public void OfficeAssignment_LinkedToInstructor()
        {
            using var context = TestDbContextFactory.Create();
            TestHelper.SeedInstructors(context);

            var instructor = context.Instructors
                .Include(i => i.OfficeAssignment)
                .First(i => i.OfficeAssignment != null);

            Assert.NotNull(instructor.OfficeAssignment);
            Assert.Equal("Smith 17", instructor.OfficeAssignment.Location);
        }

        [Fact]
        public void Enrollment_LinksCourseAndStudent()
        {
            using var context = TestDbContextFactory.Create();
            TestHelper.SeedFullData(context);

            var enrollment = context.Enrollments
                .Include(e => e.Student)
                .Include(e => e.Course)
                .First();

            Assert.NotNull(enrollment.Student);
            Assert.NotNull(enrollment.Course);
        }

        [Fact]
        public void Department_HasAdministratorNavigation()
        {
            using var context = TestDbContextFactory.Create();
            TestHelper.SeedDepartments(context);

            var dept = context.Departments
                .Include(d => d.Administrator)
                .First();

            Assert.NotNull(dept.Administrator);
        }

        [Fact]
        public void Notification_CanBeStored()
        {
            using var context = TestDbContextFactory.Create();
            context.Notifications.Add(new Notification
            {
                EntityType = "Student",
                EntityId = "1",
                Operation = "CREATE",
                Message = "Test notification",
                CreatedAt = DateTime.Now,
                CreatedBy = "admin",
                IsRead = false
            });
            context.SaveChanges();

            Assert.Single(context.Notifications);
        }

        [Fact]
        public void DbInitializer_SeedsData()
        {
            using var context = TestDbContextFactory.Create();
            DbInitializer.Initialize(context);

            Assert.True(context.Students.Any());
            Assert.True(context.Instructors.Any());
            Assert.True(context.Departments.Any());
            Assert.True(context.Courses.Any());
            Assert.True(context.Enrollments.Any());
        }

        [Fact]
        public void DbInitializer_DoesNotDuplicateData_OnSecondCall()
        {
            using var context = TestDbContextFactory.Create();
            DbInitializer.Initialize(context);
            var firstCount = context.Students.Count();

            DbInitializer.Initialize(context);
            var secondCount = context.Students.Count();

            Assert.Equal(firstCount, secondCount);
        }
    }
}
