using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Mvc;
using Microsoft.EntityFrameworkCore;
using System;
using System.Collections.Generic;
using System.Linq;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class StudentsControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly StudentsController _controller;

        public StudentsControllerTests()
        {
            _context = TestDbContextFactory.Create();
            _controller = new StudentsController(_context);
        }

        public void Dispose()
        {
            _controller.Dispose();
            _context.Dispose();
        }

        [Fact]
        public void Index_ReturnsViewResult_WithPaginatedStudents()
        {
            TestHelper.SeedStudents(_context);
            var result = _controller.Index(null, null, null, null);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsAssignableFrom<PaginatedList<Student>>(viewResult.Model);
            Assert.Equal(3, model.Count);
        }

        [Fact]
        public void Index_DefaultSort_OrdersByLastNameAscending()
        {
            TestHelper.SeedStudents(_context);
            var result = _controller.Index(null, null, null, null);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsAssignableFrom<PaginatedList<Student>>(viewResult.Model);
            Assert.Equal("Alexander", model[0].LastName);
            Assert.Equal("Alonso", model[1].LastName);
            Assert.Equal("Anand", model[2].LastName);
        }

        [Fact]
        public void Index_NameDescSort_OrdersByLastNameDescending()
        {
            TestHelper.SeedStudents(_context);
            var result = _controller.Index("name_desc", null, null, null);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsAssignableFrom<PaginatedList<Student>>(viewResult.Model);
            Assert.Equal("Anand", model[0].LastName);
        }

        [Fact]
        public void Index_DateSort_OrdersByEnrollmentDateAscending()
        {
            TestHelper.SeedStudents(_context);
            var result = _controller.Index("Date", null, null, null);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsAssignableFrom<PaginatedList<Student>>(viewResult.Model);
            Assert.Equal("Alexander", model[0].LastName); // 2020 is earliest
        }

        [Fact]
        public void Index_DateDescSort_OrdersByEnrollmentDateDescending()
        {
            TestHelper.SeedStudents(_context);
            var result = _controller.Index("date_desc", null, null, null);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsAssignableFrom<PaginatedList<Student>>(viewResult.Model);
            // 2021 dates come first (Alonso or Anand)
            Assert.True(model[0].EnrollmentDate >= model[1].EnrollmentDate);
        }

        [Fact]
        public void Index_SearchString_FiltersStudents()
        {
            TestHelper.SeedStudents(_context);
            var result = _controller.Index(null, null, "Alexander", null);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsAssignableFrom<PaginatedList<Student>>(viewResult.Model);
            Assert.Single(model);
            Assert.Equal("Alexander", model[0].LastName);
        }

        [Fact]
        public void Index_SearchByFirstName_FiltersCorrectly()
        {
            TestHelper.SeedStudents(_context);
            var result = _controller.Index(null, null, "Carson", null);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsAssignableFrom<PaginatedList<Student>>(viewResult.Model);
            Assert.Single(model);
            Assert.Equal("Carson", model[0].FirstMidName);
        }

        [Fact]
        public void Index_NewSearchString_ResetsPage()
        {
            TestHelper.SeedStudents(_context);
            var result = _controller.Index(null, null, "Al", null);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsAssignableFrom<PaginatedList<Student>>(viewResult.Model);
            Assert.Equal(1, model.PageIndex);
        }

        [Fact]
        public void Index_NullSearchString_UsesCurrentFilter()
        {
            TestHelper.SeedStudents(_context);
            var result = _controller.Index(null, "Alexander", null, null);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsAssignableFrom<PaginatedList<Student>>(viewResult.Model);
            Assert.Single(model);
        }

        [Fact]
        public void Index_SetsViewBagProperties()
        {
            TestHelper.SeedStudents(_context);
            var result = _controller.Index("Date", null, "test", null);

            var viewResult = Assert.IsType<ViewResult>(result);
            Assert.Equal("Date", viewResult.ViewData["CurrentSort"]);
            Assert.Equal("test", viewResult.ViewData["CurrentFilter"]);
            Assert.Equal("name_desc", viewResult.ViewData["NameSortParm"]);
            Assert.Equal("date_desc", viewResult.ViewData["DateSortParm"]);
        }

        [Fact]
        public void Index_EmptySortOrder_SetsNameSortParmToDesc()
        {
            TestHelper.SeedStudents(_context);
            var result = _controller.Index(null, null, null, null);
            var viewResult = Assert.IsType<ViewResult>(result);
            Assert.Equal("name_desc", viewResult.ViewData["NameSortParm"]);
        }

        [Fact]
        public void Details_ValidId_ReturnsViewWithStudent()
        {
            TestHelper.SeedStudents(_context);
            var student = _context.Students.First();

            var result = _controller.Details(student.ID);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsType<Student>(viewResult.Model);
            Assert.Equal(student.ID, model.ID);
        }

        [Fact]
        public void Details_NullId_ReturnsBadRequest()
