using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Hosting;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.EntityFrameworkCore;
using Microsoft.Extensions.Logging;
using Moq;
using System;
using System.IO;
using System.Linq;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class CoursesControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly CoursesController _controller;
        private readonly Mock<IWebHostEnvironment> _mockEnv;
        private readonly Mock<ILogger<CoursesController>> _mockLogger;
        private readonly string _tempDir;

        public CoursesControllerTests()
        {
            _context = TestDbContextFactory.Create();
            _mockEnv = new Mock<IWebHostEnvironment>();
            _mockLogger = new Mock<ILogger<CoursesController>>();
            _tempDir = Path.Combine(Path.GetTempPath(), Guid.NewGuid().ToString());
            Directory.CreateDirectory(_tempDir);
            _mockEnv.Setup(e => e.WebRootPath).Returns(_tempDir);
            _mockEnv.Setup(e => e.ContentRootPath).Returns(_tempDir);
            _controller = new CoursesController(_context, _mockEnv.Object, _mockLogger.Object);
        }

        public void Dispose()
        {
            _controller.Dispose();
            _context.Dispose();
            if (Directory.Exists(_tempDir))
            {
                try { Directory.Delete(_tempDir, true); } catch { }
            }
        }

        [Fact]
        public void Index_ReturnsViewWithCourses()
        {
            TestHelper.SeedCourses(_context);
            var result = _controller.Index();

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsAssignableFrom<System.Collections.Generic.List<Course>>(viewResult.Model);
            Assert.Equal(2, model.Count);
        }

        [Fact]
        public void Details_ValidId_ReturnsViewWithCourse()
        {
            TestHelper.SeedCourses(_context);
            var result = _controller.Details(1050);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsType<Course>(viewResult.Model);
            Assert.Equal("Chemistry", model.Title);
        }

        [Fact]
        public void Details_NullId_ReturnsBadRequest()
        {
            var result = _controller.Details(null);
            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Create_GET_ReturnsViewWithDepartmentSelectList()
        {
            TestHelper.SeedDepartments(_context);
            var result = _controller.Create();

            var viewResult = Assert.IsType<ViewResult>(result);
            Assert.NotNull(viewResult.ViewData["DepartmentID"]);
            Assert.IsType<Course>(viewResult.Model);
        }

        [Fact]
        public void Create_POST_ValidCourse_RedirectsToIndex()
        {
            TestHelper.SeedDepartments(_context);
            var dept = _context.Departments.First();
            var course = new Course
            {
                CourseID = 9999,
                Title = "New Course",
                Credits = 3,
                DepartmentID = dept.DepartmentID
            };

            var result = _controller.Create(course, null);

            var redirectResult = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirectResult.ActionName);
            Assert.NotNull(_context.Courses.Find(9999));
        }

        [Fact]
        public void Create_POST_InvalidModel_ReturnsView()
        {
            TestHelper.SeedDepartments(_context);
            _controller.ModelState.AddModelError("Title", "Required");
            var course = new Course();

            var result = _controller.Create(course, null);

            Assert.IsType<ViewResult>(result);
        }

        [Fact]
        public void Create_POST_WithValidImage_SavesFile()
        {
            TestHelper.SeedDepartments(_context);
            var dept = _context.Departments.First();
            var course = new Course { CourseID = 8888, Title = "Image Course", Credits = 3, DepartmentID = dept.DepartmentID };

            var mockFile = CreateMockFormFile("test.jpg", "image/jpeg", 1024);

            var result = _controller.Create(course, mockFile.Object);

            var redirectResult = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirectResult.ActionName);
            var savedCourse = _context.Courses.Find(8888);
            Assert.NotNull(savedCourse.TeachingMaterialImagePath);
            Assert.Contains("/Uploads/TeachingMaterials/", savedCourse.TeachingMaterialImagePath);
        }

        [Fact]
        public void Create_POST_InvalidFileExtension_ReturnsViewWithError()
        {
            TestHelper.SeedDepartments(_context);
            var dept = _context.Departments.First();
            var course = new Course { CourseID = 7777, Title = "Bad File", Credits = 3, DepartmentID = dept.DepartmentID };

            var mockFile = CreateMockFormFile("test.exe", "application/octet-stream", 1024);

            var result = _controller.Create(course, mockFile.Object);

            var viewResult = Assert.IsType<ViewResult>(result);
            Assert.True(_controller.ModelState.ContainsKey("teachingMaterialImage"));
        }

        [Fact]
        public void Create_POST_FileTooLarge_ReturnsViewWithError()
        {
            TestHelper.SeedDepartments(_context);
            var dept = _context.Departments.First();
            var course = new Course { CourseID = 6666, Title = "Large File", Credits = 3, DepartmentID = dept.DepartmentID };

            var mockFile = CreateMockFormFile("test.jpg", "image/jpeg", 6 * 1024 * 1024);

            var result = _controller.Create(course, mockFile.Object);

            var viewResult = Assert.IsType<ViewResult>(result);
            Assert.True(_controller.ModelState.ContainsKey("teachingMaterialImage"));
        }

        [Fact]
        public void Edit_GET_ValidId_ReturnsViewWithCourse()
        {
            TestHelper.SeedCourses(_context);
            var result = _controller.Edit(1050);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsType<Course>(viewResult.Model);
            Assert.Equal("Chemistry", model.Title);
            Assert.NotNull(viewResult.ViewData["DepartmentID"]);
        }

        [Fact]
        public void Edit_GET_NullId_ReturnsBadRequest()
        {
            var result = _controller.Edit(null);
            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Edit_GET_InvalidId_ReturnsNotFound()
        {
            var result = _controller.Edit(999);
            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void Edit_POST_ValidCourse_RedirectsToIndex()
        {
            TestHelper.SeedCourses(_context);
            var course = _context.Courses.AsNoTracking().First();
            course.Title = "Updated Chemistry";

            var result = _controller.Edit(course, null);

            var redirectResult = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirectResult.ActionName);
        }

        [Fact]
        public void Edit_POST_InvalidModel_ReturnsView()
        {
            TestHelper.SeedCourses(_context);
            _controller.ModelState.AddModelError("Title", "Required");
            var course = _context.Courses.AsNoTracking().First();

            var result = _controller.Edit(course, null);

            Assert.IsType<ViewResult>(result);
        }

        [Fact]
        public void Edit_POST_WithValidImage_UpdatesImagePath()
        {
            TestHelper.SeedCourses(_context);
            var course = _context.Courses.AsNoTracking().First();
            var mockFile = CreateMockFormFile("updated.png", "image/png", 2048);

            var result = _controller.Edit(course, mockFile.Object);

            var redirectResult = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirectResult.ActionName);
        }

        [Fact]
        public void Edit_POST_InvalidFileExtension_ReturnsViewWithError()
        {
            TestHelper.SeedCourses(_context);
            var course = _context.Courses.AsNoTracking().First();
            var mockFile = CreateMockFormFile("test.pdf", "application/pdf", 1024);

            var result = _controller.Edit(course, mockFile.Object);

            Assert.IsType<ViewResult>(result);
            Assert.True(_controller.ModelState.ContainsKey("teachingMaterialImage"));
        }

        [Fact]
        public void Edit_POST_FileTooLarge_ReturnsViewWithError()
        {
            TestHelper.SeedCourses(_context);
            var course = _context.Courses.AsNoTracking().First();
            var mockFile = CreateMockFormFile("big.jpg", "image/jpeg", 6 * 1024 * 1024);

            var result = _controller.Edit(course, mockFile.Object);

            Assert.IsType<ViewResult>(result);
            Assert.True(_controller.ModelState.ContainsKey("teachingMaterialImage"));
        }

        [Fact]
        public void Delete_GET_ValidId_ReturnsViewWithCourse()
        {
            TestHelper.SeedCourses(_context);
            var result = _controller.Delete(1050);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsType<Course>(viewResult.Model);
            Assert.Equal("Chemistry", model.Title);
        }

        [Fact]
        public void Delete_GET_NullId_ReturnsBadRequest()
        {
            var result = _controller.Delete(null);
            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void DeleteConfirmed_ValidId_RemovesCourseAndRedirects()
        {
            TestHelper.SeedCourses(_context);
            var initialCount = _context.Courses.Count();

            var result = _controller.DeleteConfirmed(1050);

            var redirectResult = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirectResult.ActionName);
            Assert.Equal(initialCount - 1, _context.Courses.Count());
        }

        private Mock<IFormFile> CreateMockFormFile(string fileName, string contentType, long length)
        {
            var mockFile = new Mock<IFormFile>();
            mockFile.Setup(f => f.FileName).Returns(fileName);
            mockFile.Setup(f => f.ContentType).Returns(contentType);
            mockFile.Setup(f => f.Length).Returns(length);
            mockFile.Setup(f => f.CopyTo(It.IsAny<Stream>()));
            return mockFile;
        }
    }
}

