using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Mvc;
using Microsoft.EntityFrameworkCore;
using System;
using System.Collections.Generic;
using System.Linq;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class DepartmentsControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly DepartmentsController _controller;

        public DepartmentsControllerTests()
        {
            _context = TestDbContextFactory.Create();
            _controller = new DepartmentsController(_context);
        }

        public void Dispose()
        {
            _controller.Dispose();
            _context.Dispose();
        }

        [Fact]
        public void Index_ReturnsViewWithDepartments()
        {
            TestHelper.SeedDepartments(_context);
            var result = _controller.Index();

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsAssignableFrom<List<Department>>(viewResult.Model);
            Assert.Equal(2, model.Count);
        }

        [Fact]
        public void Details_ValidId_ReturnsViewWithDepartment()
        {
            TestHelper.SeedDepartments(_context);
            var dept = _context.Departments.First();

            var result = _controller.Details(dept.DepartmentID);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsType<Department>(viewResult.Model);
            Assert.Equal(dept.Name, model.Name);
        }

        [Fact]
        public void Details_NullId_ReturnsBadRequest()
        {
            var result = _controller.Details(null);
            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Details_InvalidId_ReturnsNotFound()
        {
            var result = _controller.Details(999);
            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void Create_GET_ReturnsViewWithInstructorSelectList()
        {
            TestHelper.SeedInstructors(_context);
            var result = _controller.Create();

            var viewResult = Assert.IsType<ViewResult>(result);
            Assert.NotNull(viewResult.ViewData["InstructorID"]);
        }

        [Fact]
        public void Create_POST_ValidDepartment_RedirectsToIndex()
        {
            TestHelper.SeedInstructors(_context);
            var instructor = _context.Instructors.First();
            var dept = new Department
            {
                Name = "Physics",
                Budget = 200000,
                StartDate = DateTime.Parse("2020-09-01"),
                InstructorID = instructor.ID
            };

            var result = _controller.Create(dept);

            var redirectResult = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirectResult.ActionName);
            Assert.Single(_context.Departments);
        }

        [Fact]
        public void Create_POST_InvalidModel_ReturnsView()
        {
            TestHelper.SeedInstructors(_context);
            _controller.ModelState.AddModelError("Name", "Required");
            var dept = new Department();

            var result = _controller.Create(dept);

            var viewResult = Assert.IsType<ViewResult>(result);
            Assert.NotNull(viewResult.ViewData["InstructorID"]);
        }

        [Fact]
        public void Edit_GET_ValidId_ReturnsViewWithDepartment()
        {
            TestHelper.SeedDepartments(_context);
            var dept = _context.Departments.First();

            var result = _controller.Edit(dept.DepartmentID);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsType<Department>(viewResult.Model);
            Assert.Equal(dept.DepartmentID, model.DepartmentID);
            Assert.NotNull(viewResult.ViewData["InstructorID"]);
        }

        [Fact]
        public void Edit_GET_NullId_ReturnsBadRequest()
        {
            var result = _controller.Edit(null);
            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Edit_GET_InvalidId_ReturnsNotFound()
        {
            var result = _controller.Edit(999);
            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void Edit_POST_ValidDepartment_RedirectsToIndex()
        {
            TestHelper.SeedDepartments(_context);
            var dept = _context.Departments.AsNoTracking().First();
            dept.Name = "Updated English";

            var result = _controller.Edit(dept);

            var redirectResult = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirectResult.ActionName);
        }

        [Fact]
        public void Edit_POST_InvalidModel_ReturnsView()
        {
            TestHelper.SeedDepartments(_context);
            _controller.ModelState.AddModelError("Name", "Required");
            var dept = _context.Departments.AsNoTracking().First();

            var result = _controller.Edit(dept);

            Assert.IsType<ViewResult>(result);
        }

        [Fact]
        public void Delete_GET_ValidId_ReturnsViewWithDepartment()
        {
            TestHelper.SeedDepartments(_context);
            var dept = _context.Departments.First();

            var result = _controller.Delete(dept.DepartmentID);

            var viewResult = Assert.IsType<ViewResult>(result);
            Assert.IsType<Department>(viewResult.Model);
        }

        [Fact]
        public void Delete_GET_NullId_ReturnsBadRequest()
        {
            var result = _controller.Delete(null);
            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Delete_GET_InvalidId_ReturnsNotFound()
        {
            var result = _controller.Delete(999);
            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void DeleteConfirmed_ValidId_RemovesDepartmentAndRedirects()
        {
            TestHelper.SeedDepartments(_context);
            var dept = _context.Departments.First();
            var initialCount = _context.Departments.Count();

            var result = _controller.DeleteConfirmed(dept.DepartmentID);

            var redirectResult = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirectResult.ActionName);
            Assert.Equal(initialCount - 1, _context.Departments.Count());
        }
    }
}

