using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Mvc;
using System;
using System.Linq;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class NotificationsControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly NotificationsController _controller;

        public NotificationsControllerTests()
        {
            _context = TestDbContextFactory.Create();
            _controller = new NotificationsController(_context);
        }

        public void Dispose()
        {
            _controller.Dispose();
            _context.Dispose();
        }

        [Fact]
        public void Index_ReturnsViewResult()
        {
            var result = _controller.Index();
            Assert.IsType<ViewResult>(result);
        }

        [Fact]
        public void GetNotifications_WhenEmpty_ReturnsSuccessWithEmptyList()
        {
            // Drain any residual notifications from the shared static queue
            while (true)
            {
                var checkResult = _controller.GetNotifications();
                var checkValue = checkResult.Value;
                var countProp = checkValue.GetType().GetProperty("count");
                if ((int)countProp.GetValue(checkValue) == 0) break;
            }

            var result = _controller.GetNotifications();
            Assert.IsType<JsonResult>(result);

            var value = result.Value;
            var successProp = value.GetType().GetProperty("success");
            Assert.True((bool)successProp.GetValue(value));

            var countProperty = value.GetType().GetProperty("count");
            Assert.Equal(0, (int)countProperty.GetValue(value));
        }

        [Fact]
        public void GetNotifications_WithPendingNotifications_ReturnsNotifications()
        {
            // Send a notification via the controller's base notification service
            _controller.notificationService.SendNotification("Student", "1", "Test Student", EntityOperation.CREATE, "admin");

            var result = _controller.GetNotifications();
            var value = result.Value;

            var successProp = value.GetType().GetProperty("success");
            Assert.True((bool)successProp.GetValue(value));

            var countProp = value.GetType().GetProperty("count");
            Assert.True((int)countProp.GetValue(value) >= 1);
        }

        [Fact]
        public void MarkAsRead_ReturnsSuccess()
        {
            var result = _controller.MarkAsRead(1);

            Assert.IsType<JsonResult>(result);
            var value = result.Value;
            var successProp = value.GetType().GetProperty("success");
            Assert.True((bool)successProp.GetValue(value));
        }
    }
}

